-- ============================================================
--  Meal Planner — Supabase one-time setup
--  Paste this whole script into Supabase → SQL Editor → Run
-- ============================================================

-- 1. The dishes table
create table if not exists dishes (
  id bigint generated always as identity primary key,
  "Dish Name" text,
  "Category" text,
  "Cuisine" text,
  "Season" text,
  "Is Jain" text,
  "Cooking Time" text,
  "Meal Weight" text,
  "Protein Source" text,
  "Fiber Source" text,
  "Main Ingredients" text,
  "Preference" text,
  "Recipe URL" text,
  "Notes" text,
  created_at timestamptz default now()
);

-- 2. Open access for the family (anon key). Low-stakes shared list.
alter table dishes enable row level security;
drop policy if exists "family access" on dishes;
create policy "family access" on dishes for all to anon using (true) with check (true);

-- 3. Load all 170 dishes (only if the table is empty)
delete from dishes;
